"""
Parameterized generator for GH766_serde_3035.

Source PR:    https://github.com/serde-rs/serde/pull/3035
Source Issue: N/A

Seed varies: renames 'associated_type_usage' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH766_serde_3035'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH766_serde_3035'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('associated_type_usage', 'associated_type_usage' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH766_serde_3035',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'serde-rs/serde',
                "pr_number": 3035,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/serde-rs/serde/pull/3035",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'serde_derive/src/bound.rs': 'use crate::internals::ast::{Container, Data};\nuse crate::internals::{attr, ungroup};\nuse proc_macro2::Span;\nuse std::collections::HashSet;\nuse syn::punctuated::{Pair, Punctuated};\nuse syn::Token;\n\n// Remove the default from every type parameter because in the generated impls\n// they look like associated types: "error: associated type bindings are not\n// allowed here".\npub fn without_defaults(generics: &syn::Generics) -> syn::Generics {\n    syn::Generics {\n        params: generics\n            .params\n            .iter()\n            .map(|param| match param {\n                syn::GenericParam::Type(param) => syn::GenericParam::Type(syn::TypeParam {\n                    eq_token: None,\n                    default: None,\n                    ..param.clone()\n                }),\n                _ => param.clone(),\n            })\n            .collect(),\n        ..generics.clone()\n    }\n}\n\npub fn with_where_predicates(\n    generics: &syn::Generics,\n    predicates: &[syn::WherePredicate],\n) -> syn::Generics {\n    let mut generics = generics.clone();\n    generics\n        .make_where_clause()\n        .predicates\n        .extend(predicates.iter().cloned());\n    generics\n}\n\npub fn with_where_predicates_from_fields(\n    cont: &Container,\n    generics: &syn::Generics,\n    from_field: fn(&attr::Field) -> Option<&[syn::WherePredicate]>,\n) -> syn::Generics {\n    let predicates = cont\n        .data\n        .all_fields()\n        .filter_map(|field| from_field(&field.attrs))\n        .flat_map(<[syn::WherePredicate]>::to_vec);\n\n    let mut generics = generics.clone();\n    generics.make_where_clause().predicates.extend(predicates);\n    generics\n}\n\npub fn with_where_predicates_from_variants(\n    cont: &Container,\n    generics: &syn::Generics,\n    from_variant: fn(&attr::Variant) -> Option<&[syn::WherePredicate]>,\n) -> syn::Generics {\n    let variants = match &cont.data {\n        Data::Enum(variants) => variants,\n        Data::Struct(_, _) => {\n            return generics.clone();\n        }\n    };\n\n    let predicates = variants\n        .iter()\n        .filter_map(|variant| from_variant(&variant.attrs))\n        .flat_map(<[syn::WherePredicate]>::to_vec);\n\n    let mut generics = generics.clone();\n    generics.make_where_clause().predicates.extend(predicates);\n    generics\n}\n\n// Puts the given bound on any generic type parameters that are used in fields\n// for which filter returns true.\n//\n// For example, the following struct needs the bound `A: Serialize, B:\n// Serialize`.\n//\n//     struct S<\'b, A, B: \'b, C> {\n//         a: A,\n//         b: Option<&\'b B>\n//         #[serde(skip_serializing)]\n//         c: C,\n//     }\npub fn with_bound(\n    cont: &Container,\n    generics: &syn::Generics,\n    filter: fn(&attr::Field, Option<&attr::Variant>) -> bool,\n    bound: &syn::Path,\n) -> syn::Generics {\n    struct FindTyParams<\'ast> {\n        // Set of all generic type parameters on the current struct (A, B, C in\n        // the example). Initialized up front.\n        all_type_params: HashSet<syn::Ident>,\n\n        // Set of generic type parameters used in fields for which filter\n        // returns true (A and B in the example). Filled in as the visitor sees\n        // them.\n        relevant_type_params: HashSet<syn::Ident>,\n\n        // Fields whose type is an associated type of one of the generic type\n        // parameters.\n        associated_type_usage: Vec<&\'ast syn::TypePath>,\n    }\n\n    impl<\'ast> FindTyParams<\'ast> {\n        fn visit_field(&mut self, field: &\'ast syn::Field) {\n            if let syn::Type::Path(ty) = ungroup(&field.ty) {\n                if let Some(Pair::Punctuated(t, _)) = ty.path.segments.pairs().next() {\n                    if self.all_type_params.contains(&t.ident) {\n                        self.associated_type_usage.push(ty);\n                    }\n                }\n            }\n            self.visit_type(&field.ty);\n        }\n\n        fn visit_path(&mut self, path: &\'ast syn::Path) {\n            if let Some(seg) = path.segments.last() {\n                if seg.ident == "PhantomData" {\n                    // Hardcoded exception, because PhantomData<T> implements\n                    // Serialize and Deserialize whether or not T implements it.\n                    return;\n                }\n            }\n            if path.leading_colon.is_none() && path.segments.len() == 1 {\n                let id = &path.segments[0].ident;\n                if self.all_type_params.contains(id) {\n                    self.relevant_type_params.insert(id.clone());\n                }\n            }\n            for segment in &path.segments {\n                self.visit_path_segment(segment);\n            }\n        }\n\n        // Everything below is simply traversing the syntax tree.\n\n        fn visit_type(&mut self, ty: &\'ast syn::Type) {\n            match ty {\n                #![cfg_attr(all(test, exhaustive), deny(non_exhaustive_omitted_patterns))]\n                syn::Type::Array(ty) => self.visit_type(&ty.elem),\n                syn::Type::BareFn(ty) => {\n                    for arg in &ty.inputs {\n                        self.visit_type(&arg.ty);\n                    }\n                    self.visit_return_type(&ty.output);\n                }\n                syn::Type::Group(ty) => self.visit_type(&ty.elem),\n                syn::Type::ImplTrait(ty) => {\n                    for bound in &ty.bounds {\n                        self.visit_type_param_bound(bound);\n                    }\n                }\n                syn::Type::Macro(ty) => self.visit_macro(&ty.mac),\n                syn::Type::Paren(ty) => self.visit_type(&ty.elem),\n                syn::Type::Path(ty) => {\n                    if let Some(qself) = &ty.qself {\n                        self.visit_type(&qself.ty);\n                    }\n                    self.visit_path(&ty.path);\n                }\n                syn::Type::Ptr(ty) => self.visit_type(&ty.elem),\n                syn::Type::Reference(ty) => self.visit_type(&ty.elem),\n                syn::Type::Slice(ty) => self.visit_type(&ty.elem),\n                syn::Type::TraitObject(ty) => {\n                    for bound in &ty.bounds {\n                        self.visit_type_param_bound(bound);\n                    }\n                }\n                syn::Type::Tuple(ty) => {\n                    for elem in &ty.elems {\n                        self.visit_type(elem);\n                    }\n                }\n\n                syn::Type::Infer(_) | syn::Type::Never(_) | syn::Type::Verbatim(_) => {}\n\n                _ => {}\n            }\n        }\n\n        fn visit_path_segment(&mut self, segment: &\'ast syn::PathSegment) {\n            self.visit_path_arguments(&segment.arguments);\n        }\n\n        fn visit_path_arguments(&mut self, arguments: &\'ast syn::PathArguments) {\n            match arguments {\n                syn::PathArguments::None => {}\n                syn::PathArguments::AngleBracketed(arguments) => {\n                    for arg in &arguments.args {\n                        match arg {\n                            #![cfg_attr(all(test, exhaustive), deny(non_exhaustive_omitted_patterns))]\n                            syn::GenericArgument::Type(arg) => self.visit_type(arg),\n                            syn::GenericArgument::AssocType(arg) => self.visit_type(&arg.ty),\n                            syn::GenericArgument::Lifetime(_)\n                            | syn::GenericArgument::Const(_)\n                            | syn::GenericArgument::AssocConst(_)\n                            | syn::GenericArgument::Constraint(_) => {}\n                            _ => {}\n                        }\n                    }\n                }\n                syn::PathArguments::Parenthesized(arguments) => {\n                    for argument in &arguments.inputs {\n                        self.visit_type(argument);\n                    }\n                    self.visit_return_type(&arguments.output);\n                }\n            }\n        }\n\n        fn visit_return_type(&mut self, return_type: &\'ast syn::ReturnType) {\n            match return_type {\n                syn::ReturnType::Default => {}\n                syn::ReturnType::Type(_, output) => self.visit_type(output),\n            }\n        }\n\n        fn visit_type_param_bound(&mut self, bound: &\'ast syn::TypeParamBound) {\n            match bound {\n                #![cfg_attr(all(test, exhaustive), deny(non_exhaustive_omitted_patterns))]\n                syn::TypeParamBound::Trait(bound) => self.visit_path(&bound.path),\n                syn::TypeParamBound::Lifetime(_)\n                | syn::TypeParamBound::PreciseCapture(_)\n                | syn::TypeParamBound::Verbatim(_) => {}\n                _ => {}\n            }\n        }\n\n        // Type parameter should not be considered used by a macro path.\n        //\n        //     struct TypeMacro<T> {\n        //         mac: T!(),\n        //         marker: PhantomData<T>,\n        //     }\n        fn visit_macro(&mut self, _mac: &\'ast syn::Macro) {}\n    }\n\n    let all_type_params = generics\n        .type_params()\n        .map(|param| param.ident.clone())\n        .collect();\n\n    let mut visitor = FindTyParams {\n        all_type_params,\n        relevant_type_params: HashSet::new(),\n        associated_type_usage: Vec::new(),\n    };\n    match &cont.data {\n        Data::Enum(variants) => {\n            for variant in variants {\n                let relevant_fields = variant\n                    .fields\n                    .iter()\n                    .filter(|field| filter(&field.attrs, Some(&variant.attrs)));\n                for field in relevant_fields {\n                    visitor.visit_field(field.original);\n                }\n            }\n        }\n        Data::Struct(_, fields) => {\n            for field in fields.iter().filter(|field| filter(&field.attrs, None)) {\n                visitor.visit_field(field.original);\n            }\n        }\n    }\n\n    let relevant_type_params = visitor.relevant_type_params;\n    let associated_type_usage = visitor.associated_type_usage;\n    let new_predicates = generics\n        .type_params()\n        .map(|param| param.ident.clone())\n        .filter(|id| relevant_type_params.contains(id))\n        .map(|id| syn::TypePath {\n            qself: None,\n            path: id.into(),\n        })\n        .chain(associated_type_usage.into_iter().cloned())\n        .map(|bounded_ty| {\n            syn::WherePredicate::Type(syn::PredicateType {\n                lifetimes: None,\n                // the type parameter that is being bounded e.g. T\n                bounded_ty: syn::Type::Path(bounded_ty),\n                colon_token: <Token![:]>::default(),\n                // the bound e.g. Serialize\n                bounds: vec![syn::TypeParamBound::Trait(syn::TraitBound {\n                    paren_token: None,\n                    modifier: syn::TraitBoundModifier::None,\n                    lifetimes: None,\n                    path: bound.clone(),\n                })]\n                .into_iter()\n                .collect(),\n            })\n        });\n\n    let mut generics = generics.clone();\n    generics\n        .make_where_clause()\n        .predicates\n        .extend(new_predicates);\n    generics\n}\n\npub fn with_self_bound(\n    cont: &Container,\n    generics: &syn::Generics,\n    bound: &syn::Path,\n) -> syn::Generics {\n    let mut generics = generics.clone();\n    generics\n        .make_where_clause()\n        .predicates\n        .push(syn::WherePredicate::Type(syn::PredicateType {\n            lifetimes: None,\n            // the type that is being bounded e.g. MyStruct<\'a, T>\n            bounded_ty: type_of_item(cont),\n            colon_token: <Token![:]>::default(),\n            // the bound e.g. Default\n            bounds: vec![syn::TypeParamBound::Trait(syn::TraitBound {\n                paren_token: None,\n                modifier: syn::TraitBoundModifier::None,\n                lifetimes: None,\n                path: bound.clone(),\n            })]\n            .into_iter()\n            .collect(),\n        }));\n    generics\n}\n\npub fn with_lifetime_bound(generics: &syn::Generics, lifetime: &str) -> syn::Generics {\n    let bound = syn::Lifetime::new(lifetime, Span::call_site());\n    let def = syn::LifetimeParam {\n        attrs: Vec::new(),\n        lifetime: bound.clone(),\n        colon_token: None,\n        bounds: Punctuated::new(),\n    };\n\n    let params = Some(syn::GenericParam::Lifetime(def))\n        .into_iter()\n        .chain(generics.params.iter().cloned().map(|mut param| {\n            match &mut param {\n                syn::GenericParam::Lifetime(param) => {\n                    param.bounds.push(bound.clone());\n                }\n                syn::GenericParam::Type(param) => {\n                    param\n                        .bounds\n                        .push(syn::TypeParamBound::Lifetime(bound.clone()));\n                }\n                syn::GenericParam::Const(_) => {}\n            }\n            param\n        }))\n        .collect();\n\n    syn::Generics {\n        params,\n        ..generics.clone()\n    }\n}\n\nfn type_of_item(cont: &Container) -> syn::Type {\n    syn::Type::Path(syn::TypePath {\n        qself: None,\n        path: syn::Path {\n            leading_colon: None,\n            segments: vec![syn::PathSegment {\n                ident: cont.ident.clone(),\n                arguments: syn::PathArguments::AngleBracketed(\n                    syn::AngleBracketedGenericArguments {\n                        colon2_token: None,\n                        lt_token: <Token![<]>::default(),\n                        args: cont\n                            .generics\n                            .params\n                            .iter()\n                            .map(|param| match param {\n                                syn::GenericParam::Type(param) => {\n                                    syn::GenericArgument::Type(syn::Type::Path(syn::TypePath {\n                                        qself: None,\n                                        path: param.ident.clone().into(),\n                                    }))\n                                }\n                                syn::GenericParam::Lifetime(param) => {\n                                    syn::GenericArgument::Lifetime(param.lifetime.clone())\n                                }\n                                syn::GenericParam::Const(_) => {\n                                    panic!("Serde does not support const generics yet");\n                                }\n                            })\n                            .collect(),\n                        gt_token: <Token![>]>::default(),\n                    },\n                ),\n            }]\n            .into_iter()\n            .collect(),\n        },\n    })\n}\n',
        }
